import 'package:flutter/material.dart';

void main() => runApp(const MyApp());

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      debugShowCheckedModeBanner: false,
      theme: ThemeData(
        colorScheme: ColorScheme.fromSeed(seedColor: const Color(0xFF4CAF50)),
        useMaterial3: true,
      ),
      home: const MoreScreen(),
    );
  }
}

// ─────────────────────────────────────────────
// MODEL
// ─────────────────────────────────────────────

class Product {
  final String name;
  final String weight;
  final String price;
  final String category;
  final String description;
  final Color imageColor;

  const Product({
    required this.name,
    required this.weight,
    required this.price,
    required this.category,
    required this.description,
    required this.imageColor,
  });
}

// ─────────────────────────────────────────────
// MORE SCREEN
// ─────────────────────────────────────────────

class MoreScreen extends StatelessWidget {
  const MoreScreen({super.key});

  static const _menuItems = [
    (Icons.edit_outlined, 'Edit Profile'),
    (Icons.location_on_outlined, 'My Address'),
    (Icons.shopping_basket_outlined, 'My Orders'),
    (Icons.flash_on_outlined, 'My Wishlist'),
    (Icons.chat_bubble_outline, 'Chat with us'),
    (Icons.phone_outlined, 'Talk to our Support'),
    (Icons.mail_outline, 'Mail to us'),
    (Icons.facebook_outlined, 'Message to facebook page'),
  ];

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: Colors.white,
      body: SafeArea(
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Padding(
              padding: EdgeInsets.fromLTRB(20, 20, 20, 12),
              child: Text(
                'More',
                style: TextStyle(fontSize: 22, fontWeight: FontWeight.bold),
              ),
            ),
            // User card
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 20),
              child: Row(
                children: [
CircleAvatar(
  radius: 28,
  backgroundImage: NetworkImage(
    "https://images.unsplash.com/photo-1621761191319-c6fb62004040?q=80&w=1000",
  ),
)
,                   SizedBox(width: 12),
                  Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      const Text('Maha Abu Khater',
                          style: TextStyle(
                              fontWeight: FontWeight.bold, fontSize: 16)),
                      Container(
                        padding: const EdgeInsets.symmetric(
                            horizontal: 8, vertical: 2),
                        decoration: BoxDecoration(
                          border: Border.all(color: Colors.green),
                          borderRadius: BorderRadius.circular(4),
                        ),
                        child: const Text('0567000000',
                            style: TextStyle(fontSize: 13)),
                      ),
                    ],
                  ),
                ],
              ),
            ),
            const SizedBox(height: 16),
            // Menu list
            Expanded(
              child: ListView.separated(
                itemCount: _menuItems.length + 1, 
                separatorBuilder: (_, __) =>
                    const Divider(height: 1, indent: 20, endIndent: 20),
                itemBuilder: (context, index) {
                  if (index == _menuItems.length) {
                    return _MenuItem(
                      icon: Icons.power_settings_new,
                      label: 'Log out',
                      iconColor: Colors.red,
                      onTap: () {},
                    );
                  }
                  final item = _menuItems[index];
                  Color color = Colors.blue;
                  if (item.$1 == Icons.phone_outlined) color = Colors.orange;
                  if (item.$1 == Icons.facebook_outlined) color = Colors.blue;
                  return _MenuItem(
                    icon: item.$1,
                    label: item.$2,
                    iconColor: color,
                    onTap: index == 0
                        ? () => Navigator.push(
                              context,
                              MaterialPageRoute(
                                builder: (_) => const ProductDetailsScreen(
                                  product: Product(
                                    name: 'Aria DANO Full Cream Milk Powder Instant',
                                    weight: '1 KG',
                                    price: '\$182',
                                    category: 'Dairy Products',
                                    description:
                                        'Et quidem faciunt, ut summum bonum sit extremum et rationibus conqui sites de voluptate. Sed ut summum bonum sit id.',
                                    imageColor: Color.fromARGB(255, 43, 77, 46),
                                  ),
                                ),
                              ),
                            )
                        : () {},
                  );
                },
              ),
            ),
          ],
        ),
      ),
    );
  }
}

class _MenuItem extends StatelessWidget {
  final IconData icon;
  final String label;
  final Color iconColor;
  final VoidCallback onTap;

  const _MenuItem({
    required this.icon,
    required this.label,
    required this.iconColor,
    required this.onTap,
  });

  @override
  Widget build(BuildContext context) {
    return ListTile(
      leading: Icon(icon, color: iconColor, size: 22),
      title: Text(label, style: const TextStyle(fontSize: 15)),
      onTap: onTap,
      contentPadding: const EdgeInsets.symmetric(horizontal: 20),
      dense: true,
    );
  }
}


